extension URLSession {
    static func logRequest(request: URLRequest, response: URLResponse?, data: Data?) {
        let url = request.url?.absoluteString ?? "unknown"
        let method = request.httpMethod ?? "GET"
        let headers = request.allHTTPHeaderFields?.description ?? "nil"
        let body = request.httpBody?.utf8String ?? "nil"
        let statusCode = (response as? HTTPURLResponse)?.statusCode ?? 0
        let responseString = data?.utf8String ?? "nil"
        
        AnalyticsLogger.shared.logNetworkRequest(url: url, method: method, headers: request.allHTTPHeaderFields, body: body)
        AnalyticsLogger.shared.logAPICall(url: url, method: method, requestPayload: body, responsePayload: responseString, statusCode: statusCode)
    }
}

extension Data {
    var utf8String: String {
        return String(data: self, encoding: .utf8) ?? "nil"
    }
}

extension String {
